import{_ as e,o as l,c as i,a0 as o}from"./chunks/framework.CWk8AOcY.js";const s=JSON.parse('{"title":"什么是网络、暴露端口与访问路径","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts/network-exposure.md","filePath":"zh/guide/concepts/network-exposure.md"}'),r={name:"guide/concepts/network-exposure.md"};function t(n,a,d,h,u,b){return l(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="什么是网络、暴露端口与访问路径" tabindex="-1">什么是网络、暴露端口与访问路径 <a class="header-anchor" href="#什么是网络、暴露端口与访问路径" aria-label="Permalink to &quot;什么是网络、暴露端口与访问路径&quot;">​</a></h1><h2 id="一句话定义" tabindex="-1">一句话定义 <a class="header-anchor" href="#一句话定义" aria-label="Permalink to &quot;一句话定义&quot;">​</a></h2><p>在 CubeSandbox 中，网络不是“实例启动后顺便给一张网卡”，而是 Sandbox 可用性的关键组成部分。</p><p>这一组概念主要回答三件事：</p><ul><li>Sandbox 是否能访问外部网络</li><li>外部如何访问 Sandbox 内部服务</li><li>平台如何在隔离前提下完成这些连接</li></ul><h2 id="为什么网络在-cubesandbox-里是核心概念" tabindex="-1">为什么网络在 CubeSandbox 里是核心概念 <a class="header-anchor" href="#为什么网络在-cubesandbox-里是核心概念" aria-label="Permalink to &quot;为什么网络在 CubeSandbox 里是核心概念&quot;">​</a></h2><p>很多人会先把 CubeSandbox 看成“安全执行代码的环境”，于是容易低估网络的重要性。</p><p>但现实场景里，一个可用的 Agent Sandbox 往往需要：</p><ul><li>访问外部 API</li><li>下载依赖与模型资源</li><li>打开浏览器访问网站</li><li>对外暴露 HTTP / WebSocket / 调试端口</li><li>在平台路由下被 SDK 或代理访问</li></ul><p>如果网络只是附属功能，CubeSandbox 就只能停留在“本地 shell 沙箱”。</p><p>CubeSandbox 之所以是平台而不是命令执行器，关键之一就在于它把网络也纳入了 Sandbox 的正式抽象。</p><h2 id="先分清三层网络问题" tabindex="-1">先分清三层网络问题 <a class="header-anchor" href="#先分清三层网络问题" aria-label="Permalink to &quot;先分清三层网络问题&quot;">​</a></h2><p>理解 CubeSandbox 网络，最重要的是先把三个问题拆开。</p><h3 id="_1-sandbox-出站网络" tabindex="-1">1. Sandbox 出站网络 <a class="header-anchor" href="#_1-sandbox-出站网络" aria-label="Permalink to &quot;1. Sandbox 出站网络&quot;">​</a></h3><p>即：Sandbox 能不能主动访问外部世界。</p><p>例如：</p><ul><li><code>pip install</code></li><li>请求外部 API</li><li>浏览器访问公网</li></ul><h3 id="_2-sandbox-入站访问" tabindex="-1">2. Sandbox 入站访问 <a class="header-anchor" href="#_2-sandbox-入站访问" aria-label="Permalink to &quot;2. Sandbox 入站访问&quot;">​</a></h3><p>即：外界如何访问 Sandbox 内部服务。</p><p>例如：</p><ul><li>外部访问 Guest 中的 HTTP 服务</li><li>SDK 连接某个暴露端口</li><li>平台把域名 / 端口路由到正确实例</li></ul><h3 id="_3-平台内部网络隔离" tabindex="-1">3. 平台内部网络隔离 <a class="header-anchor" href="#_3-平台内部网络隔离" aria-label="Permalink to &quot;3. 平台内部网络隔离&quot;">​</a></h3><p>即：平台如何保证一个 Sandbox 的网络行为不会天然影响另一个 Sandbox，且不能任意探测宿主机和内网。</p><p>CubeSandbox 真正有价值的，不是单独解决其中某一个，而是把三者同时纳入统一模型。</p><h2 id="什么是-sandbox-网络视角" tabindex="-1">什么是 Sandbox 网络视角 <a class="header-anchor" href="#什么是-sandbox-网络视角" aria-label="Permalink to &quot;什么是 Sandbox 网络视角&quot;">​</a></h2><p>每个 Sandbox 并不是直接“共享宿主机网络”，而是拥有自己的虚拟网络视角。</p><p>这意味着从实例内部看：</p><ul><li>它看到的是自己的虚拟接口</li><li>它拥有自己的内部地址语义</li><li>它的出站和入站都要经过平台编排</li></ul><p>这层设计非常重要，因为它决定了：</p><ul><li>隔离可以成立</li><li>网络策略可以落在实例粒度</li><li>路由和暴露可以和平台元数据绑定</li></ul><h2 id="为什么-cubesandbox-不能直接复用-传统容器网络思路" tabindex="-1">为什么 CubeSandbox 不能直接复用“传统容器网络思路” <a class="header-anchor" href="#为什么-cubesandbox-不能直接复用-传统容器网络思路" aria-label="Permalink to &quot;为什么 CubeSandbox 不能直接复用“传统容器网络思路”&quot;">​</a></h2><p>传统容器网络在很多场景够用，但 CubeSandbox 的目标更苛刻：</p><ul><li>每个实例是强隔离 Guest</li><li>实例数量密度高</li><li>网络路径要足够轻</li><li>需要实例级安全策略</li><li>需要和端口暴露 / 域名访问紧密配合</li></ul><p>因此 CubeSandbox 把网络设计成平台核心子系统，而不是简单依赖一套通用 bridge / iptables 拼装。</p><h2 id="什么是-cubevs" tabindex="-1">什么是 CubeVS <a class="header-anchor" href="#什么是-cubevs" aria-label="Permalink to &quot;什么是 CubeVS&quot;">​</a></h2><p>在 CubeSandbox 的语境里，<strong>CubeVS</strong> 是负责实现节点侧沙箱网络虚拟化与隔离能力的关键子系统。</p><p>它的核心目标不是“提供一张虚拟网络”，而是：</p><ul><li>给每个 Sandbox 提供独立网络接入点</li><li>在内核态完成高性能转发与策略控制</li><li>支持出站访问、入站映射和隔离策略</li></ul><p>如果把 Sandbox 看成“计算对象”，那么 CubeVS 可以理解成这些计算对象的“网络平面”。</p><p>更底层的实现细节见 <a href="./../../architecture/network.html">CubeVS 网络模型</a>。</p><h2 id="什么是暴露端口-exposed-port" tabindex="-1">什么是暴露端口（Exposed Port） <a class="header-anchor" href="#什么是暴露端口-exposed-port" aria-label="Permalink to &quot;什么是暴露端口（Exposed Port）&quot;">​</a></h2><h3 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>暴露端口指的是：</p><blockquote><p>平台承认某个 Guest 内服务端口应当被外部访问路径看见，并为它建立相应映射或路由。</p></blockquote><h3 id="为什么暴露端口是平台概念而不是-guest-概念" tabindex="-1">为什么暴露端口是平台概念而不是 Guest 概念 <a class="header-anchor" href="#为什么暴露端口是平台概念而不是-guest-概念" aria-label="Permalink to &quot;为什么暴露端口是平台概念而不是 Guest 概念&quot;">​</a></h3><p>Guest 内部随便监听一个端口，并不意味着外部就能访问到它。</p><p>只有当平台：</p><ul><li>记录它</li><li>建立映射</li><li>把它纳入代理和路由逻辑</li></ul><p>它才真正成为“可访问服务入口”。</p><p>因此暴露端口不是单纯的 socket 事实，而是平台层的发布语义。</p><h2 id="什么是-probe-ready-端口" tabindex="-1">什么是 Probe / Ready 端口 <a class="header-anchor" href="#什么是-probe-ready-端口" aria-label="Permalink to &quot;什么是 Probe / Ready 端口&quot;">​</a></h2><p>一个环境“能启动”和“可服务”不是一回事。</p><p>CubeSandbox 在模板或实例层面常常需要一个准备就绪判断依据，而端口探针就是常见手段之一。</p><h3 id="它解决什么问题" tabindex="-1">它解决什么问题 <a class="header-anchor" href="#它解决什么问题" aria-label="Permalink to &quot;它解决什么问题&quot;">​</a></h3><p>它告诉平台：</p><ul><li>Guest 已经不是单纯 boot 完了</li><li>真正需要交付给用户的服务已经 ready</li><li>现在适合把这个 Sandbox 当成可用实例暴露出去</li></ul><h3 id="为什么这对-agent-场景重要" tabindex="-1">为什么这对 Agent 场景重要 <a class="header-anchor" href="#为什么这对-agent-场景重要" aria-label="Permalink to &quot;为什么这对 Agent 场景重要&quot;">​</a></h3><p>Agent 场景常常不是拿到一个 shell 就结束，而是希望环境内某个服务已经准备好了，例如：</p><ul><li>代码解释器服务</li><li>浏览器控制服务</li><li>自定义 API 端口</li></ul><p>因此 Probe 是“交付语义”的重要组成部分。</p><h2 id="外部访问路径是如何成立的" tabindex="-1">外部访问路径是如何成立的 <a class="header-anchor" href="#外部访问路径是如何成立的" aria-label="Permalink to &quot;外部访问路径是如何成立的&quot;">​</a></h2><p>从高层概念看，外界访问 Sandbox 通常要经过三步。</p><h3 id="_1-平台知道这个实例要暴露什么" tabindex="-1">1. 平台知道这个实例要暴露什么 <a class="header-anchor" href="#_1-平台知道这个实例要暴露什么" aria-label="Permalink to &quot;1. 平台知道这个实例要暴露什么&quot;">​</a></h3><p>这通常来自 Template 定义或实例元数据。</p><h3 id="_2-节点网络子系统建立到正确-guest-的映射" tabindex="-1">2. 节点网络子系统建立到正确 Guest 的映射 <a class="header-anchor" href="#_2-节点网络子系统建立到正确-guest-的映射" aria-label="Permalink to &quot;2. 节点网络子系统建立到正确 Guest 的映射&quot;">​</a></h3><p>这一步是节点侧网络执行逻辑完成的，包括端口映射与实例识别。</p><h3 id="_3-代理-域名-api-路由把请求送到正确实例" tabindex="-1">3. 代理 / 域名 / API 路由把请求送到正确实例 <a class="header-anchor" href="#_3-代理-域名-api-路由把请求送到正确实例" aria-label="Permalink to &quot;3. 代理 / 域名 / API 路由把请求送到正确实例&quot;">​</a></h3><p>这是更靠近用户入口的一层，决定“用户到底用什么地址访问到这个 Sandbox”。</p><p>也就是说，能访问一个 Sandbox，不只是它监听了端口，而是：</p><blockquote><p><strong>控制面元数据、节点网络映射和入口代理路由三者共同成立。</strong></p></blockquote><h2 id="为什么域名解析和反向代理也属于这个概念族" tabindex="-1">为什么域名解析和反向代理也属于这个概念族 <a class="header-anchor" href="#为什么域名解析和反向代理也属于这个概念族" aria-label="Permalink to &quot;为什么域名解析和反向代理也属于这个概念族&quot;">​</a></h2><p>很多用户第一次接触时会觉得：</p><ul><li>CoreDNS 是独立话题</li><li>CubeProxy 是独立话题</li><li>端口暴露是另一话题</li></ul><p>但从概念层看，它们其实共同回答的是同一个问题：</p><blockquote><p>“用户请求是如何从平台入口，被送到某个具体 Sandbox 服务上的？”</p></blockquote><p>因此：</p><ul><li>DNS 解决的是“名字如何指向入口”</li><li>Proxy 解决的是“入口如何识别目标实例并转发”</li><li>暴露端口解决的是“实例内哪个服务应被视为可访问端点”</li></ul><p>把这三者分开看，会看不懂整个访问路径。</p><h2 id="出站网络策略为什么也是核心概念" tabindex="-1">出站网络策略为什么也是核心概念 <a class="header-anchor" href="#出站网络策略为什么也是核心概念" aria-label="Permalink to &quot;出站网络策略为什么也是核心概念&quot;">​</a></h2><p>在安全沙箱场景里，“能联网”不是默认合理答案，真正重要的是：</p><ul><li>能不能联网</li><li>能访问哪些地址</li><li>哪些网段必须被拒绝</li><li>是否允许公网访问</li></ul><p>这说明网络在 CubeSandbox 里不是单纯连接能力，而是 <strong>安全策略面的一部分</strong>。</p><p>从概念上说，平台通常要能做到：</p><ul><li>对每个 Sandbox 单独施加出站控制</li><li>阻止访问宿主机与敏感内网</li><li>允许少量白名单例外</li></ul><p>这也是 CubeVS 价值的重要来源之一。</p><h2 id="访问路径里的-平台入口-和-实例入口-有什么区别" tabindex="-1">访问路径里的“平台入口”和“实例入口”有什么区别 <a class="header-anchor" href="#访问路径里的-平台入口-和-实例入口-有什么区别" aria-label="Permalink to &quot;访问路径里的“平台入口”和“实例入口”有什么区别&quot;">​</a></h2><h3 id="平台入口" tabindex="-1">平台入口 <a class="header-anchor" href="#平台入口" aria-label="Permalink to &quot;平台入口&quot;">​</a></h3><p>平台入口是用户首先接触到的地址，例如：</p><ul><li>API 地址</li><li>代理入口</li><li>域名入口</li></ul><p>它是平台级的。</p><h3 id="实例入口" tabindex="-1">实例入口 <a class="header-anchor" href="#实例入口" aria-label="Permalink to &quot;实例入口&quot;">​</a></h3><p>实例入口是最终落到具体 Sandbox 的服务端口或服务地址。</p><p>它是实例级的。</p><p>CubeSandbox 的一个关键任务，就是把平台入口正确地映射到实例入口。</p><h2 id="为什么说网络概念和调度概念是连着的" tabindex="-1">为什么说网络概念和调度概念是连着的 <a class="header-anchor" href="#为什么说网络概念和调度概念是连着的" aria-label="Permalink to &quot;为什么说网络概念和调度概念是连着的&quot;">​</a></h2><p>一个 Sandbox 被调度到哪个 Node，不只是计算资源问题，也会影响网络路径：</p><ul><li>入口最终要找到这个 Node</li><li>节点要建立到该实例的正确路由</li><li>代理和域名路径要指向实际实例位置</li></ul><p>所以网络不是调度之后才“附加”的，而是从实例落点开始就已经绑定的一部分。</p><h2 id="常见误解" tabindex="-1">常见误解 <a class="header-anchor" href="#常见误解" aria-label="Permalink to &quot;常见误解&quot;">​</a></h2><h3 id="误解一-guest-能-curl-外网-就说明网络问题都解决了" tabindex="-1">误解一：Guest 能 <code>curl</code> 外网，就说明网络问题都解决了 <a class="header-anchor" href="#误解一-guest-能-curl-外网-就说明网络问题都解决了" aria-label="Permalink to &quot;误解一：Guest 能 `curl` 外网，就说明网络问题都解决了&quot;">​</a></h3><p>不对。</p><p>出站访问只是网络能力的一部分。你还需要知道：</p><ul><li>是否受策略限制</li><li>外界能否访问 Guest 服务</li><li>平台入口是否正确映射</li><li>是否存在隔离与安全边界问题</li></ul><h3 id="误解二-监听端口就等于对外发布服务" tabindex="-1">误解二：监听端口就等于对外发布服务 <a class="header-anchor" href="#误解二-监听端口就等于对外发布服务" aria-label="Permalink to &quot;误解二：监听端口就等于对外发布服务&quot;">​</a></h3><p>不对。</p><p>监听是 Guest 内部事实；发布是平台外部语义。两者之间还差一整层映射与路由。</p><h3 id="误解三-dns-proxy-端口映射是三个互不相关的小功能" tabindex="-1">误解三：DNS / Proxy / 端口映射是三个互不相关的小功能 <a class="header-anchor" href="#误解三-dns-proxy-端口映射是三个互不相关的小功能" aria-label="Permalink to &quot;误解三：DNS / Proxy / 端口映射是三个互不相关的小功能&quot;">​</a></h3><p>不对。</p><p>它们共同构成了 CubeSandbox 的“服务可达性模型”。</p><h2 id="运维和架构视角最该关注什么" tabindex="-1">运维和架构视角最该关注什么 <a class="header-anchor" href="#运维和架构视角最该关注什么" aria-label="Permalink to &quot;运维和架构视角最该关注什么&quot;">​</a></h2><p>如果你是平台或运维角色，理解这个概念时最该抓住四个问题：</p><ol><li><strong>Sandbox 默认能否出网？</strong></li><li><strong>哪些服务端口会被平台识别为可访问入口？</strong></li><li><strong>请求是如何从域名 / 代理入口落到具体实例上的？</strong></li><li><strong>网络隔离和策略控制具体落在哪一层？</strong></li></ol><h2 id="和其它文档的关系" tabindex="-1">和其它文档的关系 <a class="header-anchor" href="#和其它文档的关系" aria-label="Permalink to &quot;和其它文档的关系&quot;">​</a></h2><ul><li>想看底层网络实现： <a href="./../../architecture/network.html">CubeVS 网络模型</a></li><li>想看 HTTPS 与域名： <a href="./../https-and-domain.html">HTTPS 证书与域名解析</a></li><li>想看节点配置与 network-agent： <a href="./../ops-manual/03-node-runtime-config.html">节点与运行时配置文件路径与说明</a></li><li>想看实例调度与节点： <a href="./node-cluster-scheduling.html">什么是 Node、集群与调度</a></li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>理解了网络路径之后，另一个最常混淆的概念族就是：</p><p><strong>镜像、文件系统、模板、可写层到底分别是什么？</strong></p><p>下一章专门把这些层次拆清楚： <a href="./filesystem-image-writable-layer.html">什么是文件系统、镜像与可写层</a>。</p>',118)])])}const c=e(r,[["render",t]]);export{s as __pageData,c as default};
